import numpy as np
from itertools import combinations, product

def generate_observable_set(n_qubits, order='single'):
    """
    Generate observables for measurement.
    """
    I = np.eye(2, dtype=complex)
    X = np.array([[0, 1], [1, 0]], dtype=complex)
    Y = np.array([[0, -1j], [1j, 0]], dtype=complex)
    Z = np.array([[1, 0], [0, -1]], dtype=complex)

    paulis = {'I': I, 'X': X, 'Y': Y, 'Z': Z}
    non_identity = ['X', 'Y', 'Z']

    def kron_n(ops):
        result = ops[0]
        for op in ops[1:]:
            result = np.kron(result, op)
        return result

    observables = []

    if order in ['single', 'all']:
        # Single-qubit Paulis
        for i in range(n_qubits):
            for p_name in non_identity:
                ops = [I] * n_qubits
                ops[i] = paulis[p_name]
                observables.append(kron_n(ops))

    if order in ['pair', 'all']:
        # Two-qubit Paulis
        for i, j in combinations(range(n_qubits), 2):
            for p1 in non_identity:
                for p2 in non_identity:
                    ops = [I] * n_qubits
                    ops[i] = paulis[p1]
                    ops[j] = paulis[p2]
                    observables.append(kron_n(ops))

    return observables

def count_observables(n_qubits):
    """Count observables for different orders."""
    n_single = 3 * n_qubits  # 3 Paulis × n qubits
    n_pair = 9 * n_qubits * (n_qubits - 1) // 2  # 3×3 × C(n,2)
    return {
        'single': n_single,
        'pair': n_pair,
        'all': n_single + n_pair
    }

# Test
for n_qubits in [3, 4, 5]:
    print(f"\n{n_qubits} qubits:")
    for order in ['single', 'pair', 'all']:
        obs = generate_observable_set(n_qubits, order)
        print(f"  Order '{order}': {len(obs)} observables")

    counts = count_observables(n_qubits)
    print(f"  Expected: {counts}")
